html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Lazy Image Loader</title>
    <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.css">
</head>
<body>
    <div class="container mx-auto p-4">
        <div class="flex flex-col items-center">
            <img class="lazyloading h-48 w-48 object-cover mb-4" src="placeholder.jpg" data-src="image1.jpg" alt="Image 1">
            <img class="lazyloading h-48 w-48 object-cover mb-4" src="placeholder.jpg" data-src="image2.jpg" alt="Image 2">
            <!-- Add more images here -->
        </div>
    </div>

    <script src="https://cdn.jsdelivr.net/npm/intersection-observer@0.12.2/intersection-observer.min.js"></script>
    <script>
        const lazyImages = document.querySelectorAll('.lazyloading');
        const observer = new IntersectionObserver((entries) => {
            entries.forEach((entry) => {
                if (entry.isIntersecting) {
                    const image = entry.target;
                    observer.unobserve(image);
                    image.src = image.dataset.src;
                }
            });
        }, {
            rootMargin: '50px',
            threshold: 1.0
        });

        lazyImages.forEach((image) => {
            observer.observe(image);
        });
    </script>
</body>
</html>
